import{c as t,Q as a,j as r,m as o}from"./chunks/framework.BPKcPtvA.js";const v=JSON.parse('{"title":"Release Archive — Ops Quick Reference","description":"","frontmatter":{},"headers":[],"relativePath":"release-archive-ops-quickref.md","filePath":"release-archive-ops-quickref.md","lastUpdated":1778829542000}'),n={name:"release-archive-ops-quickref.md"};function i(s,e,l,d,h,c){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="release-archive-—-ops-quick-reference" tabindex="-1">Release Archive — Ops Quick Reference <a class="header-anchor" href="#release-archive-—-ops-quick-reference" aria-label="Permalink to &quot;Release Archive — Ops Quick Reference&quot;">​</a></h1><p>One-page policy. No code. For the engineering doc with internals see <a href="./release-archive-and-env-retention">release-archive-and-env-retention.md</a>.</p><hr><h2 id="the-lifecycle" tabindex="-1">The lifecycle <a class="header-anchor" href="#the-lifecycle" aria-label="Permalink to &quot;The lifecycle&quot;">​</a></h2><table tabindex="0"><thead><tr><th>When</th><th>What happens</th></tr></thead><tbody><tr><td>Release completes (or fails, rolls back, is cancelled)</td><td>Full data kept indefinitely. Nothing auto-deletes.</td></tr><tr><td><strong>3 years</strong> after completion</td><td>Release is <strong>auto-archived</strong>. All data is still intact. Status shows <code>archived</code>.</td></tr><tr><td>Anytime after archive (manual or auto)</td><td>You can <strong>unarchive</strong> for <strong>30 days</strong>. Restores the prior status. Data was never touched.</td></tr><tr><td><strong>30 days</strong> after archive</td><td>Permanent purge: per-service config, env-version pin, and command logs are cleared. The release row stays. Unarchive button disappears.</td></tr></tbody></table><p>You can also <strong>manually archive</strong> any terminal release (<code>completed</code> / <code>failed</code> / <code>rolled_back</code> / <code>cancelled</code>) at any time — same 30-day clock starts when you click the button.</p><p>The sweep runs once every 24 hours.</p><hr><h2 id="what-s-kept-vs-purged" tabindex="-1">What&#39;s kept vs purged <a class="header-anchor" href="#what-s-kept-vs-purged" aria-label="Permalink to &quot;What&#39;s kept vs purged&quot;">​</a></h2><p>After the permanent purge runs, here&#39;s what&#39;s left on an archived release:</p><table tabindex="0"><thead><tr><th>Kept (forever)</th><th>Purged (at archive + 30d)</th></tr></thead><tbody><tr><td>Release name, version, type</td><td>Per-service container images</td></tr><tr><td>Release notes / changelog</td><td>Env-version pin</td></tr><tr><td>Stage approvals (who, when)</td><td>Per-instance command payloads</td></tr><tr><td>Activity log / timeline</td><td>Per-instance command replies</td></tr><tr><td>Initiator, created/deployed/completed timestamps</td><td></td></tr><tr><td>Archive timestamp</td><td></td></tr></tbody></table><p>Goal: audit story (&quot;who approved this, when&quot;) survives forever. Operational detail (&quot;which exact image went where with what env&quot;) goes away after 3y + 30d.</p><hr><h2 id="env-variable-history" tabindex="-1">Env-variable history <a class="header-anchor" href="#env-variable-history" aria-label="Permalink to &quot;Env-variable history&quot;">​</a></h2><p>Every change to an env var (default or instance override) is recorded. Cleanup runs in the same 24h sweep.</p><p>A history entry is kept if <strong>any</strong> of these is true:</p><ol><li>A release points at it.</li><li>An instance is currently running it.</li><li>It was changed less than <strong>30 days</strong> ago.</li></ol><p>Anything else gets cleaned up.</p><p><strong>Practical effect:</strong></p><ul><li>Recent edits — always browsable for at least 30 days, no matter what.</li><li>Edits tied to a release — kept as long as the release is kept (i.e. until 3y + 30d past completion).</li><li>Edits an instance is actively running — kept as long as the instance is on that version.</li></ul><hr><h2 id="common-situations" tabindex="-1">Common situations <a class="header-anchor" href="#common-situations" aria-label="Permalink to &quot;Common situations&quot;">​</a></h2><h3 id="i-archived-a-release-by-mistake" tabindex="-1">&quot;I archived a release by mistake&quot; <a class="header-anchor" href="#i-archived-a-release-by-mistake" aria-label="Permalink to &quot;&quot;I archived a release by mistake&quot;&quot;">​</a></h3><ul><li><strong>Within 30 days</strong> → open the release, click <strong>Unarchive</strong>. Status restores. Nothing was lost.</li><li><strong>After 30 days</strong> → not recoverable. Per-service config, env pin, and command logs are gone. The release record itself (name, notes, approvals, activity log) is still there. If you genuinely need the purged data, restore from backup.</li></ul><h3 id="i-need-to-see-the-env-var-diff-for-an-old-release" tabindex="-1">&quot;I need to see the env-var diff for an old release&quot; <a class="header-anchor" href="#i-need-to-see-the-env-var-diff-for-an-old-release" aria-label="Permalink to &quot;&quot;I need to see the env-var diff for an old release&quot;&quot;">​</a></h3><ul><li><strong>Release is not archived (or archived &lt;30d ago)</strong> → diff is there, view as normal.</li><li><strong>Release was purged (archived &gt;30d ago)</strong> → diff is no longer available. The UI shows an &quot;archived (permanent)&quot; banner.</li></ul><h3 id="i-need-to-see-what-i-changed-in-env-vars-last-week" tabindex="-1">&quot;I need to see what I changed in env vars last week&quot; <a class="header-anchor" href="#i-need-to-see-what-i-changed-in-env-vars-last-week" aria-label="Permalink to &quot;&quot;I need to see what I changed in env vars last week&quot;&quot;">​</a></h3><ul><li>Always works. The 30-day age floor on env-var history guarantees the last 30 days are browsable.</li></ul><h3 id="i-need-to-see-env-var-changes-from-6-months-ago" tabindex="-1">&quot;I need to see env-var changes from 6 months ago&quot; <a class="header-anchor" href="#i-need-to-see-env-var-changes-from-6-months-ago" aria-label="Permalink to &quot;&quot;I need to see env-var changes from 6 months ago&quot;&quot;">​</a></h3><ul><li>Visible if a release or a live instance still points at that version. Otherwise gone.</li></ul><h3 id="worker-isn-t-archiving-anything" tabindex="-1">&quot;Worker isn&#39;t archiving anything&quot; <a class="header-anchor" href="#worker-isn-t-archiving-anything" aria-label="Permalink to &quot;&quot;Worker isn&#39;t archiving anything&quot;&quot;">​</a></h3><ul><li>Check the worker dashboard — look for <code>release_archive</code>. It runs every 24h on the leader replica. If it shows recent runs with <code>archived: 0, purged: 0, envVersionsPruned: 0</code>, that&#39;s normal — it just means nothing was eligible this tick.</li></ul><h3 id="i-want-to-keep-a-specific-release-forever-even-past-3y" tabindex="-1">&quot;I want to keep a specific release forever, even past 3y&quot; <a class="header-anchor" href="#i-want-to-keep-a-specific-release-forever-even-past-3y" aria-label="Permalink to &quot;&quot;I want to keep a specific release forever, even past 3y&quot;&quot;">​</a></h3><ul><li>Not currently supported as a per-release flag. Workaround: manually unarchive within the 30-day window each time it auto-archives. Cleaner option (ask engineering): add a &quot;pinned&quot; boolean to skip auto-archive for that row.</li></ul><hr><h2 id="what-to-tell-users" tabindex="-1">What to tell users <a class="header-anchor" href="#what-to-tell-users" aria-label="Permalink to &quot;What to tell users&quot;">​</a></h2><blockquote><p>Releases stay fully visible for 3 years. After that they&#39;re auto-archived — still listed, still searchable, but flagged. You have 30 days from archive to unarchive if you need it back. After that, the deployment details (which image, which env vars) are cleared, but the changelog and approval history are kept forever.</p><p>Env-var history works the same way: the last 30 days are always there, and anything tied to a release or a running instance stays as long as that release or instance does.</p></blockquote><hr><h2 id="knobs-require-engineering-to-change" tabindex="-1">Knobs (require engineering to change) <a class="header-anchor" href="#knobs-require-engineering-to-change" aria-label="Permalink to &quot;Knobs (require engineering to change)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>What</th><th>Default</th></tr></thead><tbody><tr><td>Time before auto-archive</td><td>3 years</td></tr><tr><td>Unarchive window</td><td>30 days</td></tr><tr><td>Sweep frequency</td><td>24 hours</td></tr><tr><td>Env-var history floor</td><td>30 days</td></tr><tr><td>Max releases archived/purged per sweep</td><td>100</td></tr></tbody></table><p>All four time windows are constants in the codebase — straightforward edits, no schema change.</p>',41)])])}const p=t(n,[["render",i]]);export{v as __pageData,p as default};
